INSERT OR IGNORE INTO lemma (lemma_strongs, lemma_lang, lemma_word, lemma_sbl, lemma_gloss, lemma_bdb, lemma_root_strongs, lemma_explanation) VALUES ('H24', 'heb', 'אביב', 'ʼâbîyb', 'green, ear, Abib', 'אָבִיב n.m. Lv 2:14 coll. (Lag BN 207 Inf.) fresh, young ears of barley Ex 9:31; indef. Lv 2:14 מִנְחַת בִּכּוּרִים לַיהוָה א׳ קָלוּי בָּאֵשׁ. חֹדֶשׁ הָֽאָבִֽיב month of ear-forming, or of growing green, Abib, month of Exodus & passover, Ex 13:4 23:15 34:18, 18 (JE), Dt 16:1, 1 (1st month = c. April = הָרִאשֹׁן, הַחֹדֶשׁ הָר׳ (q.v.) in P; v. Di Ex 12:2; = postexilic נִיסָן q.v.) done', NULL, '');
INSERT OR IGNORE INTO lemma (lemma_strongs, lemma_lang, lemma_word, lemma_sbl, lemma_gloss, lemma_bdb, lemma_root_strongs, lemma_explanation) VALUES ('H34', 'heb', 'אביון', 'ʼebyôwn', 'destitute', 'אֶבְיוֹן adj. in want, needy, poor,—so, alw. abs., Dt 15:4 + 40 t.; אֶבְיֹנְךָ Ex 23:6 Dt 15:11; אֶבְיוֹנִים Am 4:1 + 14 t.; אֶבְיוֹנֵי (אֶבְיֹנֵי) Ex 23:11 Is 29:19; אֶבְיוֹנֶיהָ ψ 132:15—(Hex. only JED; mostly poet., 23 t. ψ) needy, chiefly poor (in material things); as adj. Dt 15:7, 7, 9; 24:14 ψ 109:16 (both ∥ עָנִי); elsewhere subst.; ψ 49:3 (∥ עָשִׁיר); Dt 15:4, 11; subj. to oppression & abuse Am 2:6 5:12 (both ∥ צַדִּיק) 4:1 8:6 (all ∥ דַּל) Is 32:7; Am 8:4 Ez 16:49 18:12 22:29 ψ 37:14 Jb 24:4, 14 Pr 30:14—cf. ψ 109:16 supr.—(all ∥ עָנִי) Je 5:28 (∥ יָתוֹם) 2:34; cared for by good Jb 29:16 30:25 (∥ קְשֵׁה־יוֹם) 31:19 ψ 112:9 Est 9:22; Pr 14:31 (∥ דָּל) 31:20 Je 22:16 (∥ עָנִי); care of them enjoined, negatively Ex 23:6;—cf. Dt 24:14 supr.—positively Ex 23:11 Dt 15:11 Pr 31:9 (both ∥ עָנִי)—cf. Dt 15:7, 7, 9 supr.—ψ 82:4 (∥ דַל); cared for by God Je 20:13 ψ 107:41 132:15 Jb 5:15; I S 2:8 = ψ 113:7 Is 14:30 (all ∥ דַּל) ψ 35:10 140:13 (both ∥ עָנִי), cf. Davidic king ψ 72:12 (∥ עָנִי) = v 4 בְנֵי אֶבְ׳ (∥ id.), v 13, 13 (∥ דַּל); needing help, deliverance from trouble, esp. as delivered by God ψ 9:19 12:6 40:18 = 70:6 74:21 86:1 109:22 Is 29:19 41:17 (all ∥ עָנִי) Is 25:4 (∥ דַּל) ψ 69:34 109:31. done', 'H14', '');
INSERT OR IGNORE INTO lemma (lemma_strongs, lemma_lang, lemma_word, lemma_sbl, lemma_gloss, lemma_bdb, lemma_root_strongs, lemma_explanation) VALUES ('H35', 'heb', 'אביונה', 'ʼăbîyôwnâh', 'provocative of desire, caper berry', 'אֲבִיּוֹנָה n.f. caper-berry (as stimulating desire) Ec 12:5 (v. GFM JBL 1891, 55 ff.; so 𝔊 𝔙, Mish. אביונות, cf. NHWB; v. also 𝔖; i.e. capparis spinosa, cf. Ri HWB; so Thes, Ew De, etc.; but Wetzst in De (Germ. ed. 1875) proposes אֶבְיוֹנָה (as fem. of אביון) the poor soul in sense = נִשְׁמָתוֹ הָאֶבְיוֹנָה cf. Symm 𝔖, where double translation). done', 'H14', '');
