INSERT OR IGNORE INTO lemma (lemma_strongs, lemma_lang, lemma_word, lemma_sbl, lemma_gloss, lemma_bdb, lemma_root_strongs, lemma_explanation) VALUES ('H3212', 'heb', 'ילך', 'yâlak', 'walk, carry', 'הָלַךְ 1546 vb. go, come, walk Qal Impf. usually (629 t.) as if from ילך lit. of persons Also of animals, in similar meanings and combinations in like manner of inanimate things The inf. abs. is often used as in other vbs., quite independently to intensify meaning of finite form most noteworthy is the joining of the Inf. abs. with a following Inf. abs. denoting a simutaneous action or process, and so emphasizing duration or continuance with a foll. vb. fin. c. ו consec. (rare) in cases where vb. fin. is foll. by Inf. abs. adj. denoting progress, advance twice, where vb. fin. is not הלך, but another vb. denoting motion quite by itself 13 t. the Inf. abs. = Imv. & is followed by Pf. consec. akin to the use of Inf. abs. are some instances of Pt. In combination with other verbal forms Fig.; the most common uses follow; in most the origin in a literal meaning is evident: pass away, die live (‘walk’), in general of moral and religious life other fig. uses Pi. (chiefly poet. and late) walk in or with a throng also of walking about = living depart, go entirely away fig. of mode of life, action, etc. Hithp. walk, walk about, move to and fro Hiph. lead, bring lead away carry, bring fig. of influence on character cause to walk, go cause to flow, run cause to depart, retire, go back base', 'H1980', '');
