INSERT OR IGNORE INTO lemma (lemma_strongs, lemma_lang, lemma_word, lemma_sbl, lemma_gloss, lemma_bdb, lemma_root_strongs, lemma_explanation) VALUES ('H3597', 'heb', 'כילף', 'kêylaph', 'club, sledge-hammer', 'כֵּילַפּוֹת n.[f.] axe (loan-word (cf. Frä 74) fr. As. kalappatu v. DI HWB 333)—בְּכַשִּׁיל וְכ׳ יַהֲלֹמ֑וּן ψ 74:6 (∥ קַרְדֻּמּֽוֹת v 5). done', NULL, '');
