INSERT OR IGNORE INTO lemma (lemma_strongs, lemma_lang, lemma_word, lemma_sbl, lemma_gloss, lemma_bdb, lemma_root_strongs, lemma_explanation) VALUES ('H3599', 'heb', 'כיס', 'kîyç', 'cup, bag', 'כִּיס n.m. Pr 1:14 bag, purse (perh. kindred with כּוֹס, q.v.; Ar. Arabic (prob. fr. Pers. Persian Lane 2640); Eth. Ethiopic NH כִּיס; Aram. כִּיסָא, Syriac; Palm. מן כיסה from his purse = at his own expense, Vog p. 13 al.)—bag, in which were carried: weights (v. אֶבֶן 5) Dt 25:13 Mi 6:11 Pr 16:11; money, i.e. a purse Is 46:6 Pr 1:14. done', NULL, '');
