INSERT OR IGNORE INTO lemma (lemma_strongs, lemma_lang, lemma_word, lemma_sbl, lemma_gloss, lemma_bdb, lemma_root_strongs, lemma_explanation) VALUES ('H3605', 'heb', 'כל', 'kôl', 'whole, all, any, every', 'כֹּל once כּוֹל n.m. the whole, all with foll. gen. (as usually) the whole of, to be rendered, however, often in our idiom, to avoid stiffness, any or every Absolutely: without the art., all things, all with the art. הַכֹּל where the sense is limited by the context to things (or persons) just mentioned in a wider sense, all, whether of all mankind or of all living things, the universe, or of all the circumstances of life (chiefly late) base', 'H3634', '');
