INSERT OR IGNORE INTO lemma (lemma_strongs, lemma_lang, lemma_word, lemma_sbl, lemma_gloss, lemma_bdb, lemma_root_strongs, lemma_explanation) VALUES ('H3607', 'heb', 'כלא', 'kâlâʼ', 'restrict, hold back, in, prohibit', '[כָּלָא] vb. shut up, restrain, withhold (NH id.; Aram. כְּלָא, Syriac; Eth. Ethiopic restrain, hinder; As. kâlû, id.; Ar. Arabic protect Qor 21:43 cf. Ba ZMG 1887, 605 Anm. 4)— Qal Pf. 3 ms. sf. כְּלָאוֹ Je 32:3; 3 fs. כָּֽלְאָה Hg 1:10; 2 fs. sf. כְּלִתִ֫נִי I S 25:33; 1 s. כָּלִאתִי ψ 119:101; 3 pl. כָּֽלְאוּ Hg 1:10, כָּלוּ I S 6:10; Impf. 3 ms. יִכְלֶה Gn 23:6; 2 ms. תִכְלָא ψ 40:12; 2 fs. תִּכְלָ֑אִי Is 43:6; 1 s. אֶכְלָא ψ 40:10; Imv. sf. כְּלָאֵֽם Nu 11:28; Inf. cstr. לִכְלוֹא Ec 8:8; Pt. pass. כָלוּא Je 32:2, כָּלֻא ψ 88:9; (on the metapl. forms, as if fr. כלה, v. Ges § 76, 21 c Kö i. 611);— shut up, c. acc. I S 6:10 (+ בְ loc.), Je 32:3; pt. pass. Je 32:2 (בְ loc.), fig. ψ 88:9 (opp. יצא). restrain, c. acc. I S 25:33 (+ מִבּוֹא בְדָמִים), ψ 119:101 (+ מִכָּל־); כְּלָאֵם (sc. מֵהִתְנַבֵּא) Nu 11:28; כ׳ שְׂפָתַי ψ 40:10; כ׳ אֶת־הָרוּחַ Ec 8:8. On ψ 74:11 v. כלה Pi. 2. withhold, כ׳ אֶת־קִבְרוֹ מִמְּךָ מִקְּבֹר מֵתֶֽךָ Gn 23:6 (P), כ׳ רַחֲמֶיךָ מִמֶּנִּי ψ 40:12, Hg 1:10 b, prob. also v a (rd. מָ֑ל for MT 𝔊 מִטָּ֑ל, We); abs. אַל־תִּכְלָאִי (sc. exiles) Is 43:6 (∥ תְּנִי). Niph. Impf. וַיִּכָּלֵא הַגֶּשֶׁם מִן־הַשָּׁמָיִם Gn 8:2 (J), and the rain from heaven was restrained, cf. וַיִּכָּלְאוּ מַיִם רַבִּים Ez 31:15 (in fig.; ∥ מנע); וַיִּכָּלֵא הָעָם מֵהָבִיא Ex 36:6 (P). Pi. [Pf. כִּלָּא and] Inf. cstr. לְכַלֵּא v. כלה Pi. done', 'H3607', '');
INSERT OR IGNORE INTO lemma (lemma_strongs, lemma_lang, lemma_word, lemma_sbl, lemma_gloss, lemma_bdb, lemma_root_strongs, lemma_explanation) VALUES ('H3608', 'heb', 'כלא', 'keleʼ', 'prison', 'כֶּ֫לֶא n.[m.] confinement, restraint, imprisonment;—abs. כ׳ 1 K 22:27 + 6 t.; sf. כִּלְאוֹ 2 K 25:29 Je 52:33; pl. כְלָאִים Is 42:22;—confinement, in combin. בֵּית (ה)כ׳ (cf. As. bit kili, prison, DI HWB 328) 1 K 22:27 = 2 Ch 18:26, 2 K 17:4 Je 37:15, 18 Is 42:7; בָּֽתֵּי כְלָאִים v 22 (cf. בָּיִת 1 (ε) (2) p. 109 supr.; v. also כלוא infr.); בִּגְדֵי כִלְאוֹ 2 K 25:29 = Je 52:33 garments of imprisonment = prison garb. done', 'H3607', '');
INSERT OR IGNORE INTO lemma (lemma_strongs, lemma_lang, lemma_word, lemma_sbl, lemma_gloss, lemma_bdb, lemma_root_strongs, lemma_explanation) VALUES ('H3610', 'heb', 'כלאים', 'kilʼayim', 'two heterogeneities', 'כִּלְאַיִם n.[m.]du. two kinds (Ar. Arabic, Arabic both; Eth. Ethiopic two; perh. also כלאי MI 23 both, two, Nö LCB 1889, 61, cf. Dr Sm xcii; Sm u. So MI, 1886 suggest reservoirs; v. also כְּלִי)—בְּהֶמְתְּךָ לֹא־תַרְבִּיעַ כ׳ Lv 19:19 not cause thy cattle to breed (in) two kinds; שָׂדְךָ לֹא תִזְרַע כ׳ v 19 (H); לֹא תִזְרַע כַּרְמְךָ כ׳ Dt 22:9 (both כִּלְאָ֑יִם); בֶגֶד כ׳ Lv 19:19 (H);—only in law of H and D against mixtures. done', 'H3607', '');
INSERT OR IGNORE INTO lemma (lemma_strongs, lemma_lang, lemma_word, lemma_sbl, lemma_gloss, lemma_bdb, lemma_root_strongs, lemma_explanation) VALUES ('H3611', 'heb', 'כלב', 'keleb', 'dog, prostitute', 'כֶּ֫לֶב n.m. I S 24:15 dog (NH id.; Ph. כלב; Aram. כֶּ֫לְבָּא, Syriac; Ar. Arabic; Eth. Ethiopic As. kalbu DI HWB 328)—abs. כ׳ Ju 7:5 + 16 t., כָּ֑לֶב ψ 59:7, 15; pl. כְּלָבִים 1 K 14:11 + 12 t.; cstr. כַּלְבֵי Jb 30:1; sf. כְּלָבֶיךָ ψ 68:24;—dog: lit. 1 K 14:11 16:4 21:19, 19, 23, 24 22:38 2 K 9:10, 36 (all of fierce, hungry dogs, devouring dead bodies and licking blood); cf. Je 15:3 and (לְשׁוֹן כְּלָבֶיךָ) ψ 68:24; eating torn flesh, Ex 22:30 (E), כַּלְבֵי צֹאנִי = my sheep-dogs, only Jb 30:1 (in both these with implied inferiority); dog-sacrifice was a heathen rite Is 66:3 (Di al.); v. esp. RS Sem. 1, 273 (291), 325 (343); in various sim. Ju 7:5 Pr 26:11, 17 ψ 59:7, 15; in proverbial sayings: לֹא יֶֽחֱרַץ־כ׳ לְשֹׁנוֹ Ex 11:7 (v. I. חרץ);לְכ׳ מֵת טוֹב מִן־הָאַרְיֵה הַמֵּֽת Ec 9:4. applied, fig., to men, in contempt I S 17:43, so of psalmist’s enemies ψ 22:17, 21, or in excessive humility 2 K 8:13; still more emphatically כ׳ מֵת a dead dog, הָכּ׳ הַמֵּת 2 S 9:8 16:9; also רֹאשׁ כ׳ 3:8; כְּלָבִים אִלְּמִים Is 56:10 (of misleading prophets), הַכּ׳ עַזֵּי נֶפֶשׁ v 11 (id.); כ׳ was name given to male temple-prostitutes Dt 23:19 (v. Dr; cf. קָדֵשׁ). done', NULL, '');
INSERT OR IGNORE INTO lemma (lemma_strongs, lemma_lang, lemma_word, lemma_sbl, lemma_gloss, lemma_bdb, lemma_root_strongs, lemma_explanation) VALUES ('H3615', 'heb', 'כלה', 'kâlâh', 'end, cease, be finished, perish, complete, prepare, consume', 'כָּלָה 204 vb. be complete, at an end, finished, accomplished, spent Qal be complete, at an end, of a period of time be completed, finished, of a work be accomplished, fulfilled be idealy complete, be determined, always in a bad sense, plotted be spent, used up (prop. come to an end), of water waste away, be exhausted, fail come to an end, vanish = perish, be destroyed Pi. complete, bring to an end, finish, a thing, task, work, etc. complete a period of time finish doing a thing make an end, end accomplish, fulfil, bring to pass accomplish in thought, determine put an end to, cause to cease cause to fail, exhaust, use up, spend destroy, sts. exterminate base', 'H3615', '');
