INSERT OR IGNORE INTO lemma (lemma_strongs, lemma_lang, lemma_word, lemma_sbl, lemma_gloss, lemma_bdb, lemma_root_strongs, lemma_explanation) VALUES ('H5920', 'heb', 'על', 'ʻal', 'top, Highest, God, aloft, to Jehovah', 'עַל, עָ֑ל subst. height As prep. upon, and hence on the ground of, according to, on account of, on behalf of, concerning, beside, in addition to, together with, beyond, above, over, by, on to, towards, to, against Upon, of the substratum upon which an object in any way rests, or on which an action is performed — of clothing, etc., which any one wears With verbs of covering or protecting, even though the cover or veil be not over or above the thing covered, but around or before it Of what rests heavily upon a person, or is a burden to him Of a duty, payment, care, etc., imposed upon a person, or devolving on him על is used idiom. to give pathos to the expression of an emotion, by emphasizing the person who is its subject, and who, as it were, feels it acting upon him חָיָה עַל to live upon (as upon a foundation or support) Of the ground or basis, on which a thing is done It expresses excess It denotes elevation or pre-eminence It expresses addition It expresses the idea of being extended, or suspended over anything, without however being in contact with it, above, over From the sense of inclining or impending over, על comes to denote contiguity or proximity, Engl. by (or sts. on) In connection with verbs of motion (actual or fig.) By writers of the silver age, על is sts. used with the force of a dative With other particles: As conj. עַל אֲשֶׁר because that עַל כִּי similar in meaning, but less frequent עַל alone: because notwithstanding that, although Compounds: with כְּ (rare and late) as concerning, as upon the like of their deeds is the like of (that which) he will repay מֵעַל from upon, from over, from by base', 'H5927', '');
INSERT OR IGNORE INTO lemma (lemma_strongs, lemma_lang, lemma_word, lemma_sbl, lemma_gloss, lemma_bdb, lemma_root_strongs, lemma_explanation) VALUES ('H5921', 'heb', 'על', 'ʻal', 'above, over, upon, against', '', 'H5927', '');
INSERT OR IGNORE INTO lemma (lemma_strongs, lemma_lang, lemma_word, lemma_sbl, lemma_gloss, lemma_bdb, lemma_root_strongs, lemma_explanation) VALUES ('H5922', 'arc', 'על', 'ʻal', 'about', 'עַל prep. upon, over, on account of, above, to, against base', 'H5922', '');
